previewCss:
.darma-loader-darma-custom-484 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #a5b4fc);
   width: fit-content;
   background: currentColor;
   padding: 0 8px;
   font-size: 30px;
   font-family: monospace;
   color: var(--loader-color, #4f46e5);
   font-weight: bold;
   border-radius: 8px;
   position: relative;
}
.darma-loader-darma-custom-484::before {
  content: "08:00";
   white-space: pre;
   animation: darma-loader-darma-custom-484-l8 .5s infinite;
}
.darma-loader-darma-custom-484::after {
  content: "";
   position: absolute;
   inset: auto auto 100% 10px;
   height: 5px;
   width: 40%;
   background: linear-gradient(90deg,var(--loader-color, #4f46e5) 40%,#0000 0 60%,var(--loader-secondary-color, #a5b4fc) 0);
}
@keyframes darma-loader-darma-custom-484-l8  {
  100% {content: " : "}
}

